  function ensureSelection() { const keys = Object.keys(state.sites); if (!state.sites[state.currentSite]) state.currentSite = keys[0] || 'cafe'; const current = site(); if (!current?.sections?.some((sec) => sec.id === state.currentSection)) state.currentSection = current?.sections?.[0]?.id || 'home'; if (!section()?.items?.some((item) => item.id === state.selectedItemId)) state.selectedItemId = null; }
  function snapshot() { return clone({ sites: state.sites, currentSite: state.currentSite, currentSection: state.currentSection, selectedItemId: state.selectedItemId }); }
  function restore(snap) { state.sites = clone(snap.sites); state.currentSite = snap.currentSite; state.currentSection = snap.currentSection; state.selectedItemId = snap.selectedItemId; ensureSelection(); writeLocal(); renderAll(); queueSave(); }
