  async function saveDraft(show = true) { writeLocal(); try { const response = await fetch('/api/johankarrd/drafts', { method: 'POST', headers: { 'content-type': 'application/json' }, body: JSON.stringify({ sites: state.sites }) }); if (!response.ok) throw new Error('save failed'); if (show) setStatus('Draft guardado en BOOSTR.'); return true; } catch (_) { if (show) setStatus('Guardado localmente. Cloud no respondió.'); return false; } }
