  function renderToolbar() { const selected = $('[data-item-id].selected', E.canvas); if (!selected || !state.selectedItemId) return E.toolbar.classList.remove('show'); const rect = selected.getBoundingClientRect(); const canvasRect = E.canvas.getBoundingClientRect(); E.toolbar.style.left = `${Math.max(8, Math.min(canvasRect.width - 230, rect.left - canvasRect.left))}px`; E.toolbar.style.top = `${Math.max(8, rect.top - canvasRect.top - 48)}px`; E.toolbar.classList.add('show'); }
